local typeofYXIMapCamera =  typeof(CardEHT.YXIMapCamera)
local YXTouchManager = CS.YXTouchManager

---@type LMapBase
local LMapBase = LMapBase

---@class LFastDreamTripMap:LMapBase
local LFastDreamTripMap = LxClass("LFastDreamTripMap",LMapBase)

function LFastDreamTripMap:LFastDreamTripMap()
    self._isMoving = false

    self._cameraStartPos = nil
    self._startMousePos = nil
end

function LFastDreamTripMap:OnDestroy()
    self:RemoveTouchEvent()
    gLGpManager:FindFastDreamTripGp():Destroy()
    LMapBase.OnDestroy(self)
end

function LFastDreamTripMap:OnCreate()
    LMapBase.OnCreate(self)
end

function LFastDreamTripMap:OnExitMap()
    gLGpManager:FindFastDreamTripGp():Destroy()
    self:RemoveTouchEvent()
end

function LFastDreamTripMap:OnResetMap()
    local mapName = "MapDreamTrip"
    self:SetMapName(mapName)
    self:DelayGuideReadyMsg()
end

function LFastDreamTripMap:OnEnterMap()
    local mapId = self:GetMapArg("mapId")
    local params = {
        mapType = self:GetMapArg("mapType"),
        mapId = self:GetMapArg("mapId"),
        mapGameId = self:GetMapArg("mapGameId"),
    }
    gLGpManager:FindFastDreamTripGp():InitFastDreamTrip(self,params)
    GF.OpenWndBottom("UIHope",{mapId = mapId})
    self:InitTouchEvent()
end

function LFastDreamTripMap:IsOverUI(screenPos)
    local touchObject = YXTouchManager.EventSystemRaycastGameObject(screenPos)
    if touchObject and gLGameUI:IsUILayer(touchObject.layer) then
        return true
    end
end

function LFastDreamTripMap:InitTouchEvent()
    local op = LGameTouch.TOUCH_WONDER
    gLGameTouch:TouchRegister(op,LGameTouch.TOUCH_EVT_START,function (screenPos)
        if self:IsOverUI(screenPos) then return end
        self._touchStart = true
    end)

    gLGameTouch:TouchRegister(op,LGameTouch.TOUCH_EVT_MOVE,function (screenPos)
        if self:IsOverUI(screenPos) then return end
        if not self._touchStart then return end

        --- 如果是在格子加载动画中，则不允许拖动
        if not gLGpManager:FindFastDreamTripGp():CheckIsCanDragCamera() then return end

        self:OnDragBegin(screenPos)
        self:OnDrag(screenPos)
    end)

    gLGameTouch:TouchRegister(op,LGameTouch.TOUCH_EVT_END,function (screenPos)
        if not self._touchStart then return end
        if self:IsOverUI(screenPos) then return end
        self:OnDragEnd()
        self._touchStart = false
    end)

    gLGameTouch:TouchRegister(op,LGameTouch.TOUCH_EVT_CANCEL,function (screenPos)
    end)
end

function LFastDreamTripMap:OnDragBegin(mousePos)
    if self._isMoving then return end

    local pos = gLGameScene:GetCurrentSceneCamera().transform.position
    self._cameraStartPos = pos
    self._startMousePos = mousePos

    self:OnDragStart()
end

function LFastDreamTripMap:OnDrag(mousePos)
    if not self._isMoving then return end
    self:DoMapCameraMove(self._startMousePos,mousePos)
end

function LFastDreamTripMap:DoMapCameraMove(startMove,mousePos)
    local offset = startMove - mousePos
    local offsetX = offset.x * 0.01 + self._cameraStartPos.x
    local offsetY = offset.y * 0.01 + self._cameraStartPos.y
    self:SetCameraPos(Vector3.New(offsetX,offsetY,0))
end

function LFastDreamTripMap:SetCameraPos(pos)
    self._mapCameraCom:ChangeCameraPos(pos)
end

function LFastDreamTripMap:OnDragStart()
    if self._isMoving then return end
    self._isMoving = true
    self._mapCameraCom:StartDrag()
end

function LFastDreamTripMap:OnDragEnd()
    if not self._isMoving then return end
    self._isMoving = false
    self._mapCameraCom:EndDrag()
end

function LFastDreamTripMap:IsOverUI(screenPos)
    local touchObject = YXTouchManager.EventSystemRaycastGameObject(screenPos)
    if touchObject and gLGameUI:IsUILayer(touchObject.layer) then
        return true
    end
end

function LFastDreamTripMap:RemoveTouchEvent()
    if gLGameTouch then gLGameTouch:TouchUnRegister(LGameTouch.TOUCH_WONDER) end
end

function LFastDreamTripMap:GetCurCameraScope()
    return gModelFastDreamTrip:GetCameraScopeByMapId(self:GetMapArg("mapId"))
end

function LFastDreamTripMap:InitCameraComponent()
    local layerRoot = CS.FindTrans(self._mapTrans,"LayerRoot")
    local com = layerRoot:GetComponent(typeofYXIMapCamera)
    self._mapCameraCom = com

    local rangeX,rangeY = self:GetCurCameraScope()
    local newRangStar = LUtil.GetCameraRange(-rangeX.x,-rangeY.x)
    local newRangEnd = LUtil.GetCameraRange(rangeX.y,rangeY.y)
    self._mapCameraCom:SetRange(Vector2.New(-newRangStar.x,-newRangStar.y),Vector2.New(newRangStar.x,newRangStar.y))
end

function LFastDreamTripMap:SetCameraFollow(transform,offset,time)
    self._mapCameraCom:StartFollowState(transform,offset,time)
end

return LFastDreamTripMap